  iz_drempel_gehaald: { nl: "Drempel bereikt — in voorbereiding", fr: "Seuil atteint — en préparation", en: "Threshold reached — in preparation", es: "Umbral alcanzado — en preparación", ru: "Порог достигнут — в подготовке" },
