  mailbeheer_logo: { nl: "Logo (URL of upload)", fr: "Logo (URL ou import)", en: "Logo (URL or upload)", es: "Logo (URL o subida)", ru: "Логотип (URL или загрузка)" },
  mailbeheer_accent: { nl: "Accentkleur", fr: "Couleur d'accent", en: "Accent colour", es: "Color de acento", ru: "Акцентный цвет" },
  mailbeheer_afzender: { nl: "Afzendernaam", fr: "Nom de l'expéditeur", en: "Sender name", es: "Nombre del remitente", ru: "Имя отправителя" },
  mailbeheer_huisstijl_uitleg: { nl: "Deze huisstijl wordt gebruikt voor alle e-mails zonder eigen white-label.", fr: "Cette identité visuelle est utilisée pour tous les e-mails sans white-label propre.", en: "This house style is used for all e-mails without their own white-label.", es: "Esta identidad visual se usa para todos los correos sin white-label propio.", ru: "Этот фирменный стиль используется для всех писем без собственного white-label." },
  mailbeheer_kies_org: { nl: "Kies een organisatie", fr: "Choisir une organisation", en: "Choose an organisation", es: "Elegir una organización", ru: "Выберите организацию" },
  mailbeheer_whitelabel_uitleg: { nl: "Stel per organisatie een eigen logo, accentkleur en afzendernaam in. Lege velden vallen terug op de algemene huisstijl.", fr: "Définissez par organisation un logo, une couleur d'accent et un nom d'expéditeur propres. Les champs vides reviennent à l'identité visuelle générale.", en: "Set a custom logo, accent colour and sender name per organisation. Empty fields fall back to the general house style.", es: "Configure un logo, un color de acento y un nombre de remitente propios por organización. Los campos vacíos vuelven a la identidad visual general.", ru: "Задайте собственный логотип, акцентный цвет и имя отправителя для каждой организации. Пустые поля возвращаются к общему фирменному стилю." },

