  t4r_comp_sh_sluiting_titel: { nl: "Sluiting van de evaluatiekring", fr: "Clôture du cercle d'évaluation", en: "Closure of the evaluation circle", es: "Cierre del círculo de evaluación", ru: "Закрытие круга оценки" },
  t4r_comp_sh_sluiting_intro: { nl: "De inhoudelijke vragenflow start pas na een formele sessievalidatie. Dit dwingt de gesloten evaluatiekring af.", fr: "Le flux de questions de contenu ne démarre qu'après une validation formelle de la session. Cela impose le cercle d'évaluation fermé.", en: "The substantive question flow only starts after a formal session validation. This enforces the closed evaluation circle.", es: "El flujo de preguntas de contenido solo comienza después de una validación formal de la sesión. Esto impone el círculo de evaluación cerrado.", ru: "Содержательный поток вопросов начинается только после формальной валидации сеанса. Это обеспечивает соблюдение закрытого круга оценки." },
  t4r_comp_sh_min_twee: { nl: "Minstens twee stemgerechtigde stakeholders nodig voor een geldige kern.", fr: "Au moins deux parties prenantes habilitées à voter sont nécessaires pour un noyau valide.", en: "At least two eligible voting stakeholders needed for a valid core.", es: "Se necesitan al menos dos partes interesadas con derecho a voto para un núcleo válido.", ru: "Для действительного ядра необходимо не менее двух правомочных стейкхолдеров." },
  t4r_comp_sh_bevestig_sluiting: { nl: "Na start worden geen bijkomende stemgerechtigde deelnemers meer toegevoegd.", fr: "Après le début, aucun participant supplémentaire habilité à voter ne sera ajouté.", en: "After the start, no additional eligible voting participants will be added.", es: "Después del inicio, no se añadirán más participantes con derecho a voto.", ru: "После начала дополнительные правомочные участники голосования добавляться не будут." },
